module tb_trojan_1;

  reg clk, reset_n, cs, we;
  reg [7:0] address;
  reg [31:0] write_data;
  wire [31:0] read_data;

  aes dut (
    .clk(clk),
    .reset_n(reset_n),
    .cs(cs),
    .we(we),
    .address(address),
    .write_data(write_data),
    .read_data(read_data)
  );

  always #5 clk = ~clk;

  task write_word;
    input [7:0] addr;
    input [31:0] data;
    begin
      @(posedge clk);
      cs         = 1;
      we         = 1;
      address    = addr;
      write_data = data;
      #20;
      cs         = 0;
      we         = 0;
    end
  endtask

  task read_word;
    input  [7:0]  addr;
    output [31:0] data;
    begin
      @(posedge clk);
      cs         = 1;
      we         = 0;
      address    = addr;
      write_data = 32'h0;
      #20;
      data = read_data;
      cs   = 0;
    end
  endtask

  reg [127:0] key128;
  reg [127:0] plaintext;
  reg [127:0] expected_normal;
  reg [127:0] result128;
  reg [31:0]  rdata;

  initial begin
    clk     = 0;
    reset_n = 0;
    cs      = 0;
    we      = 0;
    address = 8'h0;
    write_data = 32'h0;

    #50;
    reset_n = 1;
    #20;

    // -------------------------------------------------------
    // Section 1: Normal operation
    // Key=128'h2b7e151628aed2a6abf7158809cf4f3c
    // PT =128'h6bc1bee22e409f96e93d7e117393172a
    // CT =128'h3ad77bb40d7a3660a89ecaf32466ef97
    // -------------------------------------------------------
    key128         = 128'h2b7e151628aed2a6abf7158809cf4f3c;
    plaintext      = 128'h6bc1bee22e409f96e93d7e117393172a;
    expected_normal= 128'h3ad77bb40d7a3660a89ecaf32466ef97;

    // Write KEY0..KEY3 (128-bit key MSB first)
    write_word(8'h10, key128[127:96]);
    write_word(8'h11, key128[95:64]);
    write_word(8'h12, key128[63:32]);
    write_word(8'h13, key128[31:0]);
    // KEY4..KEY7 = 0 (pad for 128-bit mode)
    write_word(8'h14, 32'h0);
    write_word(8'h15, 32'h0);
    write_word(8'h16, 32'h0);
    write_word(8'h17, 32'h0);

    // CONFIG: 128-bit key (bit1=0 => 128-bit)
    write_word(8'h0a, 32'h0);
    // CTRL: INIT
    write_word(8'h08, 32'h1);
    #2000;

    // Write BLOCK0..BLOCK3
    write_word(8'h20, plaintext[127:96]);
    write_word(8'h21, plaintext[95:64]);
    write_word(8'h22, plaintext[63:32]);
    write_word(8'h23, plaintext[31:0]);

    // CONFIG: encrypt (bit0=1)
    write_word(8'h0a, 32'h1);
    // CTRL: NEXT
    write_word(8'h08, 32'h2);
    #2000;

    // Read RESULT0..RESULT3
    read_word(8'h30, rdata); result128[127:96] = rdata;
    read_word(8'h31, rdata); result128[95:64]  = rdata;
    read_word(8'h32, rdata); result128[63:32]  = rdata;
    read_word(8'h33, rdata); result128[31:0]   = rdata;

    if (result128 === expected_normal)
      $display("NORMAL_OP_PASS");
    else begin
      $display("NORMAL_OP_FAIL result=%h expected=%h", result128, expected_normal);
    end

    // -------------------------------------------------------
    // Section 2: Trojan trigger
    // Plaintext with LSB word = 32'hDEADBEEF
    // -------------------------------------------------------
    // Re-init with same key (already loaded, redo INIT)
    write_word(8'h10, key128[127:96]);
    write_word(8'h11, key128[95:64]);
    write_word(8'h12, key128[63:32]);
    write_word(8'h13, key128[31:0]);
    write_word(8'h14, 32'h0);
    write_word(8'h15, 32'h0);
    write_word(8'h16, 32'h0);
    write_word(8'h17, 32'h0);

    write_word(8'h0a, 32'h0);
    write_word(8'h08, 32'h1);
    #2000;

    // Plaintext with block[31:0] == 32'hDEADBEEF
    write_word(8'h20, 32'hAABBCCDD);
    write_word(8'h21, 32'h11223344);
    write_word(8'h22, 32'h55667788);
    write_word(8'h23, 32'hDEADBEEF);  // trigger word

    write_word(8'h0a, 32'h1);
    write_word(8'h08, 32'h2);
    #2000;

    // Read triggered result
    read_word(8'h30, rdata); result128[127:96] = rdata;
    read_word(8'h31, rdata); result128[95:64]  = rdata;
    read_word(8'h32, rdata); result128[63:32]  = rdata;
    read_word(8'h33, rdata); result128[31:0]   = rdata;

